// ============================================================
// SIM-004 — Firewall / EDR Simulator
// VERSION CORRIGÉE — CVF-001 (TOKEN_SIM)
// ============================================================
const raw  = $input.first().json;
const body = raw.body || raw;
const ts   = new Date().toISOString();

// ── TOKEN — lecture headers + body + raw ──────────────────
const receivedToken = String(
  (raw.headers && raw.headers['x-soc-token']) ||
  (raw.headers && raw.headers['X-Soc-Token']) ||
  raw['x-soc-token']  ||
  raw.soc_token       ||
  body['x-soc-token'] ||
  body.soc_token      || ''
).trim();

const SOC_TOKEN = String($vars.SIM_TOKEN || '').trim();

if (!receivedToken) {
  return [{ json: { status: 'ERROR', error: 'UNAUTHORIZED',
    message: 'Token manquant', timestamp: ts } }];
}
if (!SOC_TOKEN) {
  return [{ json: { status: 'ERROR', error: 'MISCONFIGURATION',
    message: 'Variable SIM_TOKEN non configurée', timestamp: ts } }];
}
if (receivedToken !== SOC_TOKEN) {
  return [{ json: { status: 'ERROR', error: 'UNAUTHORIZED',
    message: 'Token SOC invalide', timestamp: ts } }];
}
// ── SANITISATION ───────────────────────────────────────────
function sanitize(val) {
  return String(val || '').replace(/[|\n\r\t<>]/g, '_').substring(0, 200);
}

const action = sanitize(body.action || raw.action || 'unknown');
const ip     = sanitize(body.ip     || raw.ip     || '0.0.0.0');
const host   = sanitize(body.host   || raw.host   || 'unknown-host');
const inc_id = sanitize(body.incident_id || raw.incident_id || 'INC-UNKNOWN');

// ── VALIDATION ACTION ──────────────────────────────────────
const VALID_ACTIONS = [
  'block_ip','isolate_host','purge_phishing_emails','full_av_scan'
];
if (!VALID_ACTIONS.includes(action)) {
  return [{ json: {
    status   : 'ERROR',
    message  : 'Action invalide — autorisées: ' + VALID_ACTIONS.join(', '),
    received : action, timestamp: ts
  }}];
}

// ── PROTECTION IPs CRITIQUES ───────────────────────────────
const PROTECTED_IPS = ['0.0.0.0','127.0.0.1','::1','10.0.0.1','localhost'];
if (action === 'block_ip' && PROTECTED_IPS.includes(ip)) {
  return [{ json: {
    status   : 'ERROR', action,
    message  : 'REFUSED: Blocage IP protégée interdit — ' + ip,
    timestamp: ts
  }}];
}

console.log('[SIM-004] Action: ' + action +
  ' — IP/Host: ' + (action === 'block_ip' ? ip : host) +
  ' — IncID: ' + inc_id);

// ── RÉPONSES SIMULÉES ──────────────────────────────────────
const responses = {
  'block_ip': {
    status     : 'SUCCESS', action: 'block_ip',
    firewall   : 'PaloAlto-NGFW-01',
    policy_zone: 'INTERNET_TO_DMZ',
    rule_id    : 'RULE_BF_' + Date.now(),
    ip_blocked : ip, incident_id: inc_id,
    message    : 'IP ' + ip + ' bloquée sur toutes interfaces',
    applied_by : 'SOC_AUTO_RESPONSE', timestamp: ts
  },
  'isolate_host': {
    status    : 'SUCCESS', action: 'isolate_host',
    edr       : 'CrowdStrike-Falcon',
    agent_id  : 'AGENT_' + Math.random().toString(36).substr(2,8).toUpperCase(),
    host, incident_id: inc_id,
    isolation : 'FULL_NETWORK_ISOLATION',
    message   : 'Poste ' + host + ' isolé du réseau',
    applied_by: 'SOC_AUTO_RESPONSE', timestamp: ts
  },
  'purge_phishing_emails': {
    status       : 'SUCCESS', action: 'purge_phishing_emails',
    mail_system  : 'Microsoft-Exchange-2019',
    user         : host, incident_id: inc_id,
    emails_purged: Math.floor(Math.random() * 15) + 1,
    message      : 'Emails phishing purgés de la boîte de ' + host,
    applied_by   : 'SOC_AUTO_RESPONSE', timestamp: ts
  },
  'full_av_scan': {
    status       : 'SUCCESS', action: 'full_av_scan',
    av_engine    : 'Microsoft-Defender-ATP',
    host, incident_id: inc_id,
    scan_type    : 'FULL_DISK_SCAN',
    threats_found: 0,
    message      : 'Scan AV complet lancé sur ' + host,
    applied_by   : 'SOC_AUTO_RESPONSE', timestamp: ts
  }
};

return [{ json: responses[action] }];
